const data = items[0].json;

const hourly = data.hourly || {};
const times = hourly.time || [];
const temps = hourly.temperature_2m || [];
const precip = hourly.precipitation || [];

if (!Array.isArray(times) || !Array.isArray(temps) || temps.length === 0) {
  throw new Error('Unexpected response shape: hourly.time / hourly.temperature_2m missing');
}

const n = temps.length;

let minT = Infinity;
let maxT = -Infinity;
let sumT = 0;
let sumP = 0;
let maxP = -Infinity;

for (let i = 0; i < n; i++) {
  const t = Number(temps[i]);
  if (!Number.isFinite(t)) continue;
  if (t < minT) minT = t;
  if (t > maxT) maxT = t;
  sumT += t;

  const p = Number(precip[i] || 0);
  if (Number.isFinite(p)) {
    sumP += p;
    if (p > maxP) maxP = p;
  }
}

const avgT = sumT / n;

// simple flags (adjust thresholds as needed)
const heatAlert = maxT >= 30;         // °C
const heavyRainAlert = sumP >= 10;    // mm over forecast window

const start = times[0];
const end = times[times.length - 1];

const report = [
  `# Weather Summary (Open-Meteo)`,
  `**Location:** 40.71, -74.01 (America/New_York)`,
  `**Period:** ${start} → ${end}`,
  ``,
  `## Temperature (°C)`,
  `- Max: ${maxT.toFixed(1)}`,
  `- Min: ${minT.toFixed(1)}`,
  `- Avg: ${avgT.toFixed(1)}`,
  ``,
  `## Precipitation`,
  `- Total: ${sumP.toFixed(1)} mm`,
  `- Max hourly: ${Number.isFinite(maxP) ? maxP.toFixed(1) : 'n/a'} mm`,
  ``,
  `## Alerts`,
  `- Heat (>= 30°C): ${heatAlert ? 'YES' : 'NO'}`,
  `- Heavy rain (>= 10mm total): ${heavyRainAlert ? 'YES' : 'NO'}`
].join('\n');

return [
  {
    json: {
      metrics: {
        start,
        end,
        temp_c: { min: minT, max: maxT, avg: avgT },
        precipitation_mm: { total: sumP, max_hourly: maxP },
        alerts: { heatAlert, heavyRainAlert }
      },
      markdownReport: report
    }
  }
];
